  async syncBankAccountFromSepay(companyId: string, bankId: string): Promise<boolean> {
    const bankAccSepay = await this.sepayService.getBankAccounts(new BankAccountQuery(null, '', companyId, bankId));

    const sepayBankAccounts = bankAccSepay.data;
    const totalBankAccounts = bankAccSepay.meta.total;
    const bankAccounts = await this.repo.find({ company: { externalId: companyId }, bank: { externalId: bankId } });
    if (bankAccounts.length === totalBankAccounts) {
      this.logger.log(`syncBankAccountFromSepay:: No bank account needs to be synced.`);
      return true;
    }

    const banks = await this.bankService.findAll();
    const bankMap = new Map(banks.map(b => [b.externalId, b]));
    const companies = await this.companyService.findAll();
    const companyMap = new Map(companies.map(b => [b.externalId, b]));

    const existingBankAccounts = await this.repo.find({
      externalId: In(sepayBankAccounts.map(b => b.id)),
    });

    const existingBankAccountSet = new Set(existingBankAccounts.map(b => b.externalId));

    const newBankAccounts = sepayBankAccounts
      .filter(({ id }) => !existingBankAccountSet.has(id))
      .map(({ id, company_id, bank_id, bank_api_connected, account_holder_name, account_number }) => {
