    identificationNumber: string,
    phoneNumber: string,
  }> {
    const req: any = { code: customerCode.startsWith('OLTK') ? customerCode.slice(4) : customerCode, bankCode };
    const { webhookApiKey, agencyUrl, webhookAuthKey, webhookAuthPosition } = company;
    if (!webhookApiKey || !agencyUrl)
      this.logger.error(`getInfoByCompanyAndCode:: company not found webhookApiKey or agencyUrl: `);

    const query = new URLSearchParams();
    const headers = {
      'Content-Type': 'application/json',
    };

    if (webhookAuthPosition === WebhookAuthPosition.HEADERS) {
      headers[`${webhookAuthKey}`] = webhookApiKey;
    }
    if (webhookAuthPosition === WebhookAuthPosition.BODY) {
      req[`${webhookAuthKey}`] = webhookApiKey;
    }
    if (webhookAuthPosition === WebhookAuthPosition.QUERY) {
      query.append(`${webhookAuthKey}`, webhookApiKey);
    }

    try {
      // handle call external 
      this.logger.log(`getInfoByCompanyAndCode:: calling ${company.getInfo()} service: `,
        { webhookApiKey, agencyUrl, customerCode },
      );
      const url = `${agencyUrl}${/OLTK/i.test(customerCode) ? `` : `/${customerCode}`}?${query.toString()}`.replace(/([^:]\/)\/+/g, '$1');
      const { data } = await firstValueFrom(
        this.httpService.post<{
          agencyCode: string,
          agencyName: string,
          agencyAddress: string,
          bankAccountNo: string,
          identificationNumber: string,
          phoneNumber: string,
        }>(url, req, { headers }).pipe(
          catchError((error: AxiosError) => {
            const temp = error?.response?.data || error?.message || error;
            this.logger.error(`getInfoByCompanyAndCode:: calling ${company.getInfo()} service failed: `,
              {
                url,
                req,
                headers,
                error: temp,
              },
            );
            throw new Error(`calling ${company.getInfo()} service failed ~ ${JSON.stringify(temp)}`);
          }),
        ),
      );
      return {
        ...data,
        customerCode,

      };
    } catch (error) {
      this.logger.error(`getInfoByCompanyAndCode:: handle fail reason: `, error.message || error);
      throw new NotFoundException(ErrorCode.CUSTOMER_CODE_NOT_FOUND);
    }
  }

  async syncVaName(id: number) {
    const item = await this.repo.findOneExist({ id }, ['company', 'bank']);
    if (item.bank.code === 'ABB') {
      // Call AG to get VA name
      const va = await this.getInfoByCompanyAndCode(item.company, item.bankAccountNo.startsWith('BGTA') ? item.bankAccountNo.slice(4) : item.bankAccountNo, item.bank.code);
      this.logger.log(`syncVaName:: get info from AG ${item.bankAccountNo}: `, va);

      item.bankAccountName = va.agencyName;
      await this.repo.partialUpdateById(item.id, { bankAccountName: va.agencyName, bankAccountNo: va.bankAccountNo });
      // Call ABB
      const req: UpdateVaDto = {
        records: [
          {
            'personId': va.customerCode,
            'personName': va.agencyName,
            'status': 1,
          },
        ],
      };
      if (item.company.shortName === 'OLTK') await this.anBinhBankService.updateVA('BGTA', req);
      else
        await this.anBinhBankService.updateVA(item.company.shortName, req);
    }
    return item;
  }
