@Injectable()
export class CompanyService {
  private readonly logger = new ADLogger(CompanyService.name);

  constructor(
    private readonly repo: CompanyRepository,
    @Inject('ISepayService')
    private readonly sepay: ISepayService,
    @InjectAppConfig()
    private readonly config: AppConfig,
    private readonly auditLogService: AuditLogService,
  ) { }
  async create(createCompanyDto: CreateCompanyDto, user?: User) {
    await this.repo.checkExist({ email: createCompanyDto.email });
    const item = new Company();
    const { name, shortName } = createCompanyDto;
    Object.assign(item, createCompanyDto);
    // create company on sepay
    const rsSepay = await this.sepay.createCompany(name, shortName);
    item.externalId = rsSepay.id;
    const rs = await this.repo.create(item);

    // add audit log
    const data = {
      action: AuditLogAction.CREATE,
      feature: Feature.COMPANY,
      referenceId: String(rs.id),
      refResource: RefResource.COMPANY,
      newValue: JSON.stringify(createCompanyDto),
      modifiedBy: user,
    };
    this.auditLogService.create(data).catch(err => this.logger.warn('create COMPANY:: create audit log err:', err));

    return rs;
  }

  findAll() {
    return this.repo.findAll();
  }

  find(query: CompanyQueryParams) {
    const filter = query.getQuery();

    if (query.search) {
      filter['name'] = Raw((e) => `unaccent(${e}) ILIKE unaccent(:search)`, { search: `%${query.search}%` });
    }
    return this.repo.findAndCount(filter, query.skip(), query.take(), query.order(), query.getRelations());
  }

  findById(id: number) {
    return this.repo.findById(id, ['bankAccounts', 'bankAccounts.bank']);
  }

  findByShortName(shortName: string) {
    return this.repo.findOne({ shortName: shortName?.toUpperCase() }, ['bankAccounts', 'bankAccounts.bank']);
  }

  findOneExist(id: number) {
    return this.repo.findOneExist({ id }, ['bankAccounts', 'bankAccounts.bank']);
  }

  findOLTKInfo() {
    return this.repo.findOneExist({ shortName: 'OLTK' });
  }
  findByExternalId(externalId: string) {
    return this.repo.findOne({ externalId });
  }

  async update(id: number, updateCompanyDto: UpdateCompanyDto, user?: User) {
    const item = await this.repo.findOneExist({ id });
    if (user && user.role === Role.Admin) {
      // call Sepay update
      const CONFIG_KEYS = new Set([
        'paymentCode',
        'paymentCodePrefix',
        'paymentCodeSuffixCharacterType',
        'paymentCodeSuffixFrom',
        'paymentCodeSuffixTo',
        'transactionAmount',
      ]);

      const INFO_KEYS = new Set([
        'name',
        'shortName',
        'status',
      ]);

      if (Object.keys(updateCompanyDto).some(key => CONFIG_KEYS.has(key))) {
        await this.sepay.configurationCompany(item.externalId,
          {
            payment_code: updateCompanyDto.paymentCode || item.paymentCode,
            payment_code_prefix: updateCompanyDto.paymentCodePrefix || item.paymentCodePrefix,
            payment_code_suffix_from: updateCompanyDto.paymentCodeSuffixFrom || item.paymentCodeSuffixFrom,
            payment_code_suffix_to: updateCompanyDto.paymentCodeSuffixTo || item.paymentCodeSuffixTo,
            payment_code_suffix_character_type:
              updateCompanyDto.paymentCodeSuffixCharacterType || item.paymentCodeSuffixCharacterType,
            transaction_amount: updateCompanyDto.transactionAmount || item.transactionAmount,
          });
      }
      if (Object.keys(updateCompanyDto).some(key => INFO_KEYS.has(key))) {
        await this.sepay.updateCompany(item.externalId,
          {
            full_name: updateCompanyDto.name || item.name,
            short_name: updateCompanyDto.shortName || item.shortName,
            status: updateCompanyDto.status || item.status as any,
          });
      }
    }
    // add audit log
    const oldValue = Object.keys(updateCompanyDto).reduce((acc, key) => {
      acc[key] = item[key];
      return acc;
    }, {});
    const data = {
      action: AuditLogAction.UPDATE,
      feature: Feature.COMPANY,
      referenceId: String(id),
      refResource: RefResource.COMPANY,
      oldValue: JSON.stringify(oldValue),
      newValue: JSON.stringify(updateCompanyDto),
      modifiedBy: user,
    };
    this.auditLogService.create(data).catch(err => this.logger.warn('update COMPANY :: create audit log err:', err));

    return this.repo.updateOne({ id }, updateCompanyDto);
  }

  async remove(id: number, user?: User) {
    const item = await this.repo.findOneExist({ id });
    // add audit log
    const data = {
      action: AuditLogAction.DELETE,
      feature: Feature.COMPANY,
      referenceId: String(id),
      refResource: RefResource.COMPANY,
      oldValue: JSON.stringify(item),
      modifiedBy: user,
    };
    this.auditLogService.create(data).catch(err => this.logger.warn('delete COMPANY:: create audit log err:', err));

    return this.repo.remove({ id });
  }

  async getDefaultCompany() {
    let defaultCompany = await this.repo.findOne({});
    if (defaultCompany)
      return defaultCompany;
    defaultCompany = await this.repo.create(this.config.migration.company as Company);
    return defaultCompany;
  }
}

