import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Brackets, Repository } from 'typeorm';

import { BankAccount } from '@bank-account/entities';

import { TypeORMRepository } from '@infra/database/repository';

import { BankAccountQueryParams } from './dto';

@Injectable()
export class BankAccountRepository extends TypeORMRepository<BankAccount> {
  constructor(
    @InjectRepository(BankAccount)
    readonly repository: Repository<BankAccount>,
  ) {
    super(repository);
  }
  async findByQueryBuilder(query: BankAccountQueryParams) {
    const qb = this.repository.createQueryBuilder('t');

    // relations
    const relations = Array.from(new Set(query.getRelations()));
    if (relations.length === 0) {
      relations.push('bank');
      relations.push('company');
    }
    relations.forEach((relation) => {
      qb.leftJoinAndSelect(`t.${relation}`, relation);
    });

    // search
    if (query.search) {
      const search = `%${query.search}%`;
      qb.andWhere(
        new Brackets((qb1) => {
          qb1
            .where(`unaccent(t.bankAccountName) ILIKE unaccent(:search)`, { search })
            .orWhere(`t.bankAccountNo ILIKE :search`, { search });
        }),
      );
    }

    if (query.company) {
      qb.andWhere(`t.company_id = :company`, { company: query.company.id });
    }

    if (query.status) {
      qb.andWhere(`t.status = :status`, { status: query.status });
    }

    // ordering
    const order = query.order();
    if (order) {
      Object.entries(order).forEach(([field, direction]) => {
        qb.addOrderBy(`t.${field}`, direction.toUpperCase() as 'ASC' | 'DESC');
      });
    }

    // pagination
    qb.skip(query.skip()).take(query.take());
    // execute
    return qb.getManyAndCount();
  }
}

