  private getSyncCustomerCode(bankAccountNo: string, bankCode: string) {
    if (bankCode === 'ABB' && bankAccountNo?.startsWith('BGTA')) {
      return bankAccountNo.slice(4);
    }
    return bankAccountNo;
  }

  private async syncAbbVa(company: Company, customerCode: string, agencyName: string) {
    const req: UpdateVaDto = {
      records: [
        {
          personId: customerCode,
          personName: agencyName,
          status: 1,
        },
      ],
    };

    if (company.shortName === 'OLTK') {
      await this.anBinhBankService.updateVA('BGTA', req);
      return;
    }

    await this.anBinhBankService.updateVA(company.shortName, req);
  }

  async syncVaName(id: number) {
    const item = await this.repo.findOneExist({ id }, ['company', 'bank']);
    const customerCode = this.getSyncCustomerCode(item.bankAccountNo, item.bank.code);
    const va = await this.getInfoByCompanyAndCode(item.company, customerCode, item.bank.code);
    this.logger.log(`syncVaName:: get info from company ${item.bankAccountNo}: `, va);

    const syncedBankAccount = {
      bankAccountName: va.agencyName || item.bankAccountName,
      bankAccountNo: va.bankAccountNo || item.bankAccountNo,
      identificationNumber: va.identificationNumber || item.identificationNumber,
      phoneNumber: va.phoneNumber || item.phoneNumber,
    };

    await this.repo.partialUpdateById(item.id, syncedBankAccount);
    Object.assign(item, syncedBankAccount);

    if (item.bank.code === 'ABB') {
      await this.syncAbbVa(item.company, va.customerCode, syncedBankAccount.bankAccountName);
    }

    return item;
  }
}

